## Recursion & Backtracking

Backtracking systematically explores all possibilities by making choices, exploring, and undoing (backtracking) when a path doesn't work.

### The Template
```python
def backtrack(candidates, path, result):
    if is_solution(path):
        result.append(path[:])  # copy!
        return
    for choice in candidates:
        if is_valid(choice, path):
            path.append(choice)      # make choice
            backtrack(candidates, path, result)  # explore
            path.pop()               # undo choice (backtrack)
```

### Subsets
```python
def subsets(nums):
    result = []
    def backtrack(start, path):
        result.append(path[:])
        for i in range(start, len(nums)):
            path.append(nums[i])
            backtrack(i + 1, path)
            path.pop()
    backtrack(0, [])
    return result
```

### Permutations
```python
def permutations(nums):
    result = []
    def backtrack(path, remaining):
        if not remaining:
            result.append(path[:])
            return
        for i in range(len(remaining)):
            path.append(remaining[i])
            backtrack(path, remaining[:i] + remaining[i+1:])
            path.pop()
    backtrack([], nums)
    return result
```

### N-Queens
```python
def solve_n_queens(n):
    result = []
    def backtrack(row, cols, diag1, diag2, board):
        if row == n:
            result.append([''.join(r) for r in board])
            return
        for col in range(n):
            if col in cols or (row-col) in diag1 or (row+col) in diag2:
                continue
            board[row][col] = 'Q'
            backtrack(row+1, cols|{col}, diag1|{row-col}, diag2|{row+col}, board)
            board[row][col] = '.'
    backtrack(0, set(), set(), set(), [['.']*n for _ in range(n)])
    return result
```

### Key Problems
- #78 Subsets, #46 Permutations, #39 Combination Sum
- #51 N-Queens, #79 Word Search, #37 Sudoku Solver

### Interview Tip
"Backtracking is DFS with pruning. The key is knowing WHEN to prune — every valid pruning condition dramatically reduces the search space."

**Java Implementation:**

```java
// Recursion & Backtracking in Java
import java.util.*;

public class BacktrackingBasics {
    // Subsets (LC 78)
    public static List<List<Integer>> subsets(int[] nums) {
        List<List<Integer>> result = new ArrayList<>();
        backtrackSubsets(nums, 0, new ArrayList<>(), result);
        return result;
    }
    static void backtrackSubsets(int[] nums, int start, List<Integer> path, List<List<Integer>> result) {
        result.add(new ArrayList<>(path));
        for (int i = start; i < nums.length; i++) {
            path.add(nums[i]);
            backtrackSubsets(nums, i + 1, path, result);
            path.remove(path.size() - 1);
        }
    }

    // Permutations (LC 46)
    public static List<List<Integer>> permute(int[] nums) {
        List<List<Integer>> result = new ArrayList<>();
        backtrackPerm(nums, new boolean[nums.length], new ArrayList<>(), result);
        return result;
    }
    static void backtrackPerm(int[] nums, boolean[] used, List<Integer> cur, List<List<Integer>> result) {
        if (cur.size() == nums.length) { result.add(new ArrayList<>(cur)); return; }
        for (int i = 0; i < nums.length; i++) {
            if (used[i]) continue;
            used[i] = true; cur.add(nums[i]);
            backtrackPerm(nums, used, cur, result);
            used[i] = false; cur.remove(cur.size() - 1);
        }
    }

    // Fast Power — O(log n)
    public static double myPow(double x, int n) {
        if (n == 0) return 1;
        if (n < 0) { x = 1 / x; n = -n; }
        if (n % 2 == 0) { double half = myPow(x, n / 2); return half * half; }
        return x * myPow(x, n - 1);
    }

    public static void main(String[] args) {
        System.out.println("Subsets of [1,2,3]: " + subsets(new int[]{1,2,3}).size()); // 8
        System.out.println("Permutations of [1,2,3]: " + permute(new int[]{1,2,3}).size()); // 6
        System.out.printf("2^10 = %.0f%n", myPow(2, 10)); // 1024
    }
}
```
